for filename, questions in batch_data.items():
    filepath = os.path.join(botany_dir, filename)
    
    if not os.path.exists(filepath):
        print(f"File {filename} not found, skipping.")
        continue
        
    with open(filepath, 'r', encoding='utf-8') as f:
        data = json.load(f)
        
    existing_qs = data.get('questions', [])
    start_id = len(existing_qs) + 1
    
    for i, q in enumerate(questions):
        q['id'] = start_id + i
        # Ensure other fields are present
        if 'hasDiagram' not in q: q['hasDiagram'] = False
        if 'diagram_description' not in q: q['diagram_description'] = ""
        existing_qs.append(q)
        
    # Re-index all to be safe and ensure cap at 80 (well, in this case it might exceed if I add too many, but the counts were checked)
    # Actually, I should ensure it ends at EXACTLY 80 for the attempts splitting later.
    # Evolution: 60 + 20 = 80
    # Molecular: 60 + 20 = 80
    # Cell Unit: 59 + 21 = 80 (Wait, I only have 20 in the script, I'll fix that)
    # Env Issues: 59 + 21 = 80 (I'll fix that)
    # Bio/Cons: 58 + 22 = 80 (I'll fix that)

    data['questions'] = existing_qs[:80]
    
    with open(filepath, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=2, ensure_ascii=False)
        
    print(f"Updated {filename}: Total Questions = {len(data['questions'])}")
